hound.on('user.welcome', async (ctx) => {
  // ctx.data is typed to this handler's payload shape
  await sendEmail(ctx.data.email);
});

hound.on('order.fulfill', async (ctx) => {
  ctx.logger('Reserving inventory...');
  await reserveInventory(ctx.data.items);

  ctx.logger('Charging payment...');
  await chargeCard(ctx.data.paymentToken);

  ctx.logger('Sending confirmation email...');
  await sendConfirmation(ctx.data.email);
});

hound.on('user.register', async (ctx) => {
  await createUser(ctx.data);

  ctx.emit('user.welcome', { email: ctx.data.email });
  ctx.emit('analytics.track', { event: 'signup', userId: ctx.data.id });
});

hound.on(
  'payment.charge',
  async (ctx) => {
    if (!ctx.data.token) throw new Error('Missing payment token');
    await stripe.charge(ctx.data);
  },
  { attempts: 5, retryBackoff: 'exponential', retryDelayMs: 1_000 }
);
